export function SundaSiger({ className, width = 60, height = 45, color = 'var(--as-secondary)', ...props }) {
    // Siger Sunda (traditional Sundanese bridal crown with golden arch, emerald gemstones, and hanging jasmine)
    return (
        <svg
            width={width}
            height={height}
            viewBox="0 0 120 90"
            fill="none"
            xmlns="http://www.w3.org/2000/svg"
            className={className}
            style={{ display: 'block', overflow: 'visible', ...props.style }}
            {...props}
        >
            {/* Siger main arch structure */}
            <path
                d="M 10,65 C 25,65 35,50 45,35 C 50,25 55,10 60,10 C 65,10 70,25 75,35 C 85,50 95,65 110,65 C 100,70 80,72 60,72 C 40,72 20,70 10,65 Z"
                fill={color}
            />
            {/* Inner filigree engravings */}
            <path
                d="M 60,18 L 57,28 L 63,28 Z M 50,38 L 47,48 L 53,48 Z M 70,38 L 67,48 L 73,48 Z M 35,52 C 32,52 30,55 30,58 C 30,61 32,63 35,63 Z M 85,52 C 88,52 90,55 90,58 C 90,61 88,63 85,63 Z"
                fill="var(--as-primary)"
            />
            {/* Gems */}
            <circle cx="60" cy="8" r="3" fill="var(--as-primary)" stroke={color} strokeWidth="1" />
            <circle cx="45" cy="32" r="2.5" fill="var(--as-primary)" stroke={color} strokeWidth="1" />
            <circle cx="75" cy="32" r="2.5" fill="var(--as-primary)" stroke={color} strokeWidth="1" />
            <circle cx="28" cy="48" r="2" fill="var(--as-primary)" stroke={color} strokeWidth="1" />
            <circle cx="92" cy="48" r="2" fill="var(--as-primary)" stroke={color} strokeWidth="1" />
            {/* Jasmine drops */}
            <path d="M 12,65 Q 12,85 8,85" stroke={color} strokeWidth="1.5" strokeLinecap="round" />
            <circle cx="8" cy="87" r="1.5" fill="var(--as-primary)" />
            <path d="M 108,65 Q 108,85 112,85" stroke={color} strokeWidth="1.5" strokeLinecap="round" />
            <circle cx="112" cy="87" r="1.5" fill="var(--as-primary)" />
        </svg>
    );
}

