// 6. Story / Timeline Card
function TimelineCard({ story, language }) {
    const ref = useRef(null);
    const [isActive, setIsActive] = useState(false);

    useEffect(() => {
        const el = ref.current;
        if (!el) return;

        const observer = new IntersectionObserver(([entry]) => {
            setIsActive(entry.isIntersecting);
        }, {
            rootMargin: '-30% 0px -30% 0px',
            threshold: 0
        });

        observer.observe(el);
        return () => observer.disconnect();
    }, []);

    return (
        <div ref={ref} className={`as-timeline-card ${isActive ? 'is-active' : ''}`}>
            <div className="as-timeline-dot flex items-center justify-center">
                <SundaFlowerHanger className="as-timeline-lantern-icon" style={{ width: '18px', height: 'auto' }} />
            </div>
            {story.story_date && (
                <div className="as-timeline-date">{formatDate(story.story_date, language)}</div>
            )}
            <h3 className="as-timeline-title">{story.title}</h3>
            {story.description && (
                <p className="as-timeline-desc">{story.description}</p>
            )}
        </div>
    );
}

